sys_variable_value.value:
(function execute(inputs, outputs) {
  var certificateService = new CertificateService();
  var error = certificateService.pickUpCertificate(inputs.requestId, inputs.certificateRequestGr);
  outputs.error = error;
})(inputs, outputs);

